const { env } = require('@nordic/env');

const TIMEOUT = env.FURY && env.PRODUCTION ? 3000 : 10000;

const WEB_SEC_SCOPE = env.SCOPE || 'local';
const WEB_SEC_BASE_URL =
  env.FURY && env.PRODUCTION
    ? 'http://secure-defaults.melisystems.com'
    : 'https://secure-defaults.melioffice.com';

module.exports = {
  RESTCLIENT_TIMEOUT: TIMEOUT,
  RESTCLIENT_WEB_SEC_SCOPE: WEB_SEC_SCOPE,
  RESTCLIENT_WEB_SEC_BASE_URL: WEB_SEC_BASE_URL,
};
